import React from 'react';
import { Outlet, NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const NAV_ITEMS = [
  { to: '/dashboard', label: 'Dashboard', icon: '◉', roles: ['OWNER', 'READER', 'VOLUNTEER'] },
  { to: '/libraries', label: 'Libraries', icon: '⊞', roles: ['OWNER', 'READER', 'VOLUNTEER'] },
  { to: '/books', label: 'Books', icon: '◫', roles: ['OWNER', 'READER', 'VOLUNTEER'] },
  { to: '/requests', label: 'Requests', icon: '◎', roles: ['OWNER', 'READER', 'VOLUNTEER'] },
];

export default function Layout() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const visibleNav = NAV_ITEMS.filter((n) => n.roles.includes(user?.role));

  return (
    <div className="app-shell">
      <aside className="sidebar">
        <div className="sidebar-logo">
          <h1>Ba Boook Corner</h1>
          <span>Ba Foundation</span>
        </div>
        <nav className="sidebar-nav">
          {visibleNav.map((item) => (
            <NavLink
              key={item.to}
              to={item.to}
              className={({ isActive }) => (isActive ? 'active' : '')}
            >
              <span>{item.icon}</span>
              {item.label}
            </NavLink>
          ))}
        </nav>
        <div className="sidebar-user">
          <div className="name">{user?.full_name}</div>
          <div className="role">{user?.role}</div>
          <button
            className="nav-btn"
            onClick={handleLogout}
            style={{ marginTop: 10, padding: '6px 0', color: 'rgba(250,247,242,0.5)' }}
          >
            ⎋ Sign out
          </button>
        </div>
      </aside>
      <main className="main-content">
        <Outlet />
      </main>
    </div>
  );
}
